class Solution:
    def findMinimumOperations(self, s1: str, s2: str, s3: str) -> int:
        i, j, k = len(s1) - 1, len(s2) - 1, len(s3) - 1
        while i >= 0 and j >= 0 and k >= 0:
            if s1[i] == s2[j] == s3[k]:
                i -= 1
                j -= 1
                k -= 1
            elif s1[i] == s2[j]:
                k -= 1
            elif s2[j] == s3[k]:
                i -= 1
            elif s1[i] == s3[k]:
                j -= 1
            else:
                return -1
        return len(s1[:i+1]) + len(s2[:j+1]) + len(s3[:k+1])
